namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(
    PredictionEnginePool&lt;TicketData, TicketPrediction&gt; predictionPool) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult&lt;TicketClassificationResult&gt; Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority &lt; 1 || request.Priority &gt; 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionPool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidence = new Dictionary&lt;string, float&gt;();
        for (int i = 0; i &lt; labels.Length &amp;&amp; i &lt; prediction.Score.Length; i++)
            confidence[labels[i]] = prediction.Score[i];

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }
}

